import{_ as n,o as t,c as r,an as i}from"./chunks/framework.D5fFzH9V.js";const g=JSON.parse('{"title":"Datenschutzerklärung","description":"Datenschutzerklärung für handbook.syslifters.com","frontmatter":{"description":"Datenschutzerklärung für handbook.syslifters.com","search":false},"headers":[],"relativePath":"de/datenschutz.md","filePath":"de/datenschutz.md"}'),s={name:"de/datenschutz.md"};function a(d,e,u,l,h,o){return t(),r("div",null,[...e[0]||(e[0]=[i('<div style="display:none;" hidden="true" aria-hidden="true">Are you an LLM? You can read better optimized documentation at /de/datenschutz.md for this page in Markdown format</div><h1 id="datenschutzerklarung" tabindex="-1">Datenschutzerklärung <a class="header-anchor" href="#datenschutzerklarung" aria-label="Permalink to &quot;Datenschutzerklärung&quot;">​</a></h1><p>Der Schutz deiner persönlichen Daten ist uns bei Syslifters ein besonderes Anliegen. Wir verarbeiten deine Daten daher ausschließlich auf Grundlage der gesetzlichen Bestimmungen (DSGVO, TKG 2003). In diesen Datenschutzinformationen informieren wir dich über die wichtigsten Aspekte der Datenverarbeitung im Rahmen unserer Website.</p><p>Diese Datenschutzerklärung gilt für handbook.syslifters.com und ist ab 1. Juni 2022 gültig.<br> ‍</p><h2 id="hosting" tabindex="-1">Hosting <a class="header-anchor" href="#hosting" aria-label="Permalink to &quot;Hosting&quot;">​</a></h2><p>Wir hosten die Website bei GitHub. Anbieter ist die GitHub B.V., Prins Bernhardplein 200, Amsterdam, 1097JB, Niederlande (nachfolgend: GitHub). Wenn du die Website besuchst, erfasst GitHub verschiedene Logfiles inklusive deiner IP-Adressen.</p><p>Details entnehme bitte der <a href="https://docs.github.com/en/site-policy/privacy-policies/github-privacy-statement" target="_blank" rel="noreferrer">Datenschutzerklärung von GitHub</a>.</p><p>Die Verwendung von GitHub erfolgt auf Grundlage von Art. 6 Abs. 1 lit. f DSGVO. Wir haben ein berechtigtes Interesse an einer möglichst zuverlässigen Darstellung unserer Website. Sofern eine entsprechende Einwilligung abgefragt wurde, erfolgt die Verarbeitung ausschließlich auf Grundlage von Art. 6 Abs. 1 lit. a DSGVO, soweit die Einwilligung die Speicherung von Cookies oder den Zugriff auf Informationen im Endgerät des Nutzers (z. B. Device-Fingerprinting) umfasst. Die Einwilligung ist jederzeit widerrufbar.<br> ‍</p><h2 id="deine-rechte" tabindex="-1">Deine Rechte <a class="header-anchor" href="#deine-rechte" aria-label="Permalink to &quot;Deine Rechte&quot;">​</a></h2><p>Dir stehen grundsätzlich die Rechte auf Auskunft, Berichtigung, Löschung, Einschränkung, Datenübertragbarkeit, Widerruf und Widerspruch zu. Wenn du glaubst, dass die Verarbeitung deiner Daten gegen das Datenschutzrecht verstößt oder deiner datenschutzrechtlichen Ansprüche sonst in einer Weise verletzt worden sind, hast du das Recht eine Beschwerde bei der Aufsichtsbehörde einzureichen. In Österreich ist das die Datenschutzbehörde, E-Mail: <a href="mailto:dsb@dsb.gv.at" target="_blank" rel="noreferrer">dsb@dsb.gv.at</a>, Web: <a href="https://www.dsb.gv.at/" target="_blank" rel="noreferrer">https://www.dsb.gv.at/</a>.</p><h2 id="anderungen-dieser-datenschutzerklarung" tabindex="-1">Änderungen dieser Datenschutzerklärung <a class="header-anchor" href="#anderungen-dieser-datenschutzerklarung" aria-label="Permalink to &quot;Änderungen dieser Datenschutzerklärung&quot;">​</a></h2><p>Wir behalten uns das Recht vor, unsere Datenschutzerklärung bei Bedarf zu ändern, falls dies zum Beispiel aufgrund technischer Entwicklungen oder rechtlicher Änderungen notwendig sein sollte. Die jeweils aktuellste Version der Datenschutzerklärung findest du auf unserer Webseite veröffentlicht. Bitte stelle sicher, dass dir die aktuellste Version vorliegt.</p><p>Du erreichst uns unter folgenden Kontaktdaten:</p><p>Syslifters GmbH<br> Eitzersthal 75, 2013 Göllersdorf<br> E-Mail: <a href="mailto:hello@syslifters.com">hello@syslifters.com</a><br> Telefon: +43 660 923 40 60</p><p>‍<strong>Stand:</strong> 01. Juni 2022</p>',15)])])}const b=n(s,[["render",a]]);export{g as __pageData,b as default};
